import{_ as a,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"野球拳","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/野球拳.md","filePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/野球拳.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/肉搏类/野球拳.md"};function p(l,r,b,_,i,c){return t(),n("div",null,[...r[0]||(r[0]=[e("h1",{id:"野球拳",tabindex:"-1"},[s("野球拳 "),e("a",{class:"header-anchor",href:"#野球拳","aria-label":'Permalink to "野球拳"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调017")])])],-1),o('<h1 id="野球拳-1" tabindex="-1">野球拳 <a class="header-anchor" href="#野球拳-1" aria-label="Permalink to &quot;野球拳&quot;">​</a></h1><p>野球拳<br> 前置条件：拥有内力、气或灵气等东方能量池<br> （出自单机游戏《金庸群侠传》）<br> 概述：天下无难事，只怕野球拳，虾米武功高，一拳天地小。</p><p>野球拳<br> D+500<br> 描述：摆起架势，打出平平无奇的一拳，事实上，这确实就是平平无奇的一拳，哪怕练到深处，也不会有多大的改变，在诸多世界之中，传说只有一人将其练至满级，而只有那时，此拳才会展现出真正的力量。<br> 效果：使用野球拳需附带在一次标准动作的肉搏攻击上，但并不占用招式，打出一拳，这一拳平平无奇，没有任何加成。<br> 当你购买该技艺时，该技艺视为1级，当你打出一次野球拳时，积累1次攻击次数，每打出65次野球拳，你的野球拳提升1级，这会使你的野球拳命中检定获得1dp招式加值，每一场影片最多提升2次，在主神的加持下，这个招式的等级上限为无限。<br> 特殊的，你可以在战斗外打野球拳，这会占用你长休息/短休息的时间，或者任何能够在原地打拳的时间，每一分钟视为打出10拳。<br> 以附带有野球拳的技艺进行攻击时，敌人总是会感觉你的攻击像个不懂拳法的菜鸟，这没有任何实质性的效果，只会让有知性的敌人觉得用这种三脚猫功夫的你很菜。<br> 当你的野球拳升级到10级时，可以购买下一阶段的野球拳：</p><p>满级野球拳<br> B+2000<br> 前置条件：野球拳十级<br> 描述：你成为了多元宇宙中又一个把野球拳打满的彪……少侠。现在，你会让人知道什么叫做真正的，一天下无难事，只怕野球拳。<br> 效果：这一击在D级的基础上，额外获得1点附加成功，以及等同于力量属性点的技艺加值，若没有在攻击时消耗能量，画面表现为毫无内力波动的一拳直接将受击者周遭空气震出波动，若这次攻击消耗能量，则被攻击者将不由自主地感觉到自身内力（或其他能量）被这一拳轰至拨乱躁动，这不会有任何实质效果，只会让敌人觉得你是个高手。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=a(d,[["render",p]]);export{f as __pageData,m as default};
